questions.sparql:
PREFIX : <http://airdata.org/ontology#>
SELECT DISTINCT ?aircraft ?label WHERE {
  ?aircraft rdfs:subClassOf* :Aircraft .
  OPTIONAL { ?aircraft rdfs:label ?label }
}

PREFIX : <http://airdata.org/ontology#>
SELECT DISTINCT ?property WHERE {
  ?property rdfs:domain :Aerodrome .
  ?property rdfs:range :Operation .
}

PREFIX : <http://airdata.org/ontology#>
SELECT DISTINCT ?class WHERE {
  ?class a owl:Class .
  FILTER NOT EXISTS {
    ?class rdfs:label ?label .
    FILTER(lang(?label) = "pt" || lang(?label) = "pt-br")
  }
}

PREFIX : <http://airdata.org/ontology#>
SELECT DISTINCT ?dataProp ?domain ?range WHERE {
  ?dataProp a owl:DatatypeProperty .
  OPTIONAL { ?dataProp rdfs:domain ?domain }
  OPTIONAL { ?dataProp rdfs:range ?range }
}

PREFIX : <http://airdata.org/ontology#>
SELECT DISTINCT ?class ?restriction ?property WHERE {
  ?class rdfs:subClassOf ?restriction .
  ?restriction a owl:Restriction .
  ?restriction owl:onProperty ?property .
  { ?restriction owl:cardinality ?card }
  UNION
  { ?restriction owl:minCardinality ?card }
  UNION
  { ?restriction owl:maxCardinality ?card }
}

PREFIX : <http://airdata.org/ontology#>
SELECT DISTINCT ?subProp ?label WHERE {
  ?subProp rdfs:subPropertyOf :FlightOperation .
  OPTIONAL { ?subProp rdfs:label ?label }
}

PREFIX : <http://airdata.org/ontology#>
SELECT DISTINCT ?entity ?externalEntity WHERE {
  ?entity owl:sameAs ?externalEntity .
  FILTER(isURI(?externalEntity))
}

PREFIX : <http://airdata.org/ontology#>
SELECT DISTINCT ?funcProp ?label WHERE {
  ?funcProp a owl:FunctionalProperty .
  OPTIONAL { ?funcProp rdfs:label ?label }
}
